INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b46c13c1-a0c7-4660-b2b2-951fed2abb0a',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST API Design — Resource Naming, Verbs, Status Codes, and Idempotency Done Right$escape$,
  $escape$REST resource URLs should be nouns, never verbs. Use `/orders/42/items` not `/getOrderItems`. Collections are plural; singletons are singular. HTTP verbs carry the action: GET (safe + idempotent), PUT (idempotent, full replace), PATCH (partial update, not guaranteed idempotent), POST (non-idempotent, creates subordinate resource), DELETE (idempotent). Idempotency means calling the same request N times produces the same server state as calling it once — critical for retry logic. PUT `/orders/42` with the same body twice must not create a second order. POST `/orders` will. Status codes must be precise: 201 Created (with Location header) on POST success, 200 OK for GET/PUT responses with a body, 204 No Content for DELETE or PUT with no response body, 409 Conflict when a resource already exists, 422 Unprocessable Entity for valid JSON with invalid business rules, 404 only when the resource genuinely doesn't exist. Never return 200 with an error payload — that breaks every HTTP client and monitoring tool.$escape$,
  $escape$# Correct REST endpoint design

# Resource naming: nouns, plural, hierarchical
GET    /users/99/orders          # list orders for user 99
GET    /users/99/orders/42       # fetch single order
POST   /users/99/orders          # create order (non-idempotent)
PUT    /users/99/orders/42       # full replace (idempotent)
PATCH  /users/99/orders/42       # partial update
DELETE /users/99/orders/42       # delete (idempotent)

# Status code contract
# POST   → 201 Created  + Location: /users/99/orders/42
# PUT    → 200 OK       (body) or 204 No Content
# DELETE → 204 No Content
# PATCH  → 200 OK       (updated resource)
# 409    → duplicate resource; 422 → invalid business rule$escape$,
  $escape$bash$escape$,
