INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '68b437fd-ab22-43f5-9ca5-aab79a94c4ac',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST to GraphQL — Schema Design, Resolvers, N+1, and Subscriptions$escape$,
  $escape$GraphQL flips REST's resource-per-endpoint model into a single `/graphql` endpoint driven by a typed SDL schema. Where REST exposes `GET /users/:id/posts`, GraphQL lets clients declare exactly the fields needed — no over-fetching, no underfetching.

Each SDL field maps to a resolver function — think of it as a per-field route handler. `Query.users` resolves the list; `User.posts` resolves the nested relation. This composability is where REST developers trip: nested resolvers fire once per parent node.

The N+1 problem: 100 users → 100 `User.posts` resolver calls → 100 separate queries. DataLoader fixes this with tick-window batching — it collects all `userId` keys within a single request tick, then fires one `WHERE user_id = ANY($1)`.

Subscriptions replace REST polling. Define a `Subscription` type in SDL, publish via `pubSub.publish('POST_ADDED', payload)`, and clients connect over WebSocket — no more `GET /feed?since=` loops.

Critical migration gotcha: REST auth middleware on a single route doesn't translate. Apply JWT verification in the context factory (`context: ({ req }) => ({ user: verifyJWT(req) })`), not at the HTTP layer — otherwise unauthenticated introspection queries bypass your guards entirely.$escape$,
  $escape$import DataLoader from 'dataloader';
import { db } from './db';

// Instantiate per-request — never as a module-level singleton
const createPostLoader = () =>
  new DataLoader<string, Post[]>(async (userIds) => {
    const posts = await db.query(
      'SELECT * FROM posts WHERE user_id = ANY($1)',
      [userIds]
    );
    // Must return results in same order as input keys
    return userIds.map(id => posts.filter(p => p.user_id === id));
  });

// Resolver wiring
const resolvers = {
  User: {
    posts: (parent: User, _args: unknown, ctx: Context) =>
      ctx.loaders.post.load(parent.id),
  },
};$escape$,
