INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7c3ae10a-a6b3-4f08-aca5-8728dcff3223',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST vs tRPC — End-to-End Type Safety Without the Schema Sync Tax$escape$,
  $escape$tRPC eliminates the type-safety gap that plagues REST APIs. Where REST forces you to manually maintain OpenAPI schemas or write separate client-side type definitions, tRPC infers types directly from your router — no codegen, no drift.

Procedures come in three forms: `query` (GET-equivalent, React Query-cached), `mutation` (POST/PUT/DELETE-equivalent), and `subscription` (WebSocket-backed). Each accepts a Zod input schema; the return type flows to the client automatically via the shared `AppRouter` type.

React Query integration is built-in, not bolted on. `trpc.user.byId.useQuery({ id })` wraps `useQuery` under the hood — you get cache keys, stale-time, and `trpc.user.byId.invalidate()` without extra wiring. Mutations use `useMutation` with identical ergonomics.

The constraint: tRPC demands a TypeScript monorepo or shared package so server and client share the `AppRouter` type. For public REST APIs consumed externally, OpenAPI stays the right call. For internal full-stack TypeScript apps, tRPC eliminates an entire class of runtime bugs that no amount of REST discipline can prevent.$escape$,
  $escape$// server/router.ts
const appRouter = router({
  user: router({
    byId: publicProcedure
      .input(z.object({ id: z.string() }))
      .query(({ input }) => db.user.findUnique({ where: { id: input.id } })),

    create: publicProcedure
      .input(z.object({ name: z.string(), email: z.string().email() }))
      .mutation(({ input }) => db.user.create({ data: input })),
  }),
});

// client — fully typed, no extra setup
const { data } = trpc.user.byId.useQuery({ id: "123" });
await utils.user.byId.invalidate();$escape$,
  $escape$typescript$escape$,
