INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fa21197a-fb42-49aa-b836-0cb2ec423c49',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST Rate Limiting — Sliding Window vs Token Bucket Per Endpoint, Per User$escape$,
  $escape$REST APIs expose rate limiting via response headers: `X-RateLimit-Limit`, `X-RateLimit-Remaining`, `X-RateLimit-Reset`, and `Retry-After` on 429s. How you enforce those limits internally changes behavior dramatically.

Token bucket allows bursting: a user can fire 20 requests instantly if they've accumulated tokens, then refill at 5 req/s. Ideal for `POST /uploads` or `POST /ai/generate` — bursty by nature. Sliding window is stricter: it tracks request timestamps in a rolling window, so 100 req/min means no more than 100 in any 60-second slice, not just per clock-minute. Preferred for `GET /feed` or `GET /search` to prevent thundering-herd abuse.

Per-endpoint granularity matters. A REST API should never apply one global limiter — `POST /auth/login` deserves aggressive limits (5/min per IP), while `GET /users/{id}` can afford 300/min per authenticated user. Attach limiters at the route level, keyed on `user_id` from the JWT or IP for unauthenticated routes. Store state in Redis with atomic Lua scripts to avoid race conditions across replicas.$escape$,
  $escape$// Express + ioredis: sliding window per-user, per-route
import { Redis } from 'ioredis';
const redis = new Redis();

async function slidingWindowLimit(userId: string, route: string, limit: number, windowMs: number): Promise<boolean> {
  const key = `rl:${route}:${userId}`;
  const now = Date.now();
  const windowStart = now - windowMs;

  const count = await redis
    .multi()
    .zremrangebyscore(key, '-inf', windowStart)
    .zadd(key, now, `${now}-${Math.random()}`)
    .zcard(key)
    .expire(key, Math.ceil(windowMs / 1000))
    .exec();

  const requestCount = count?.[2]?.[1] as number;
  return requestCount <= limit;
}

// Usage on a specific REST endpoint
app.post('/ai/generate', async (req, res) => {
  const allowed = await slidingWindowLimit(req.user.id, 'ai:generate', 10, 60_000);
  if (!allowed) return res.status(429).set('Retry-After', '60').json({ error: 'Rate limit exceeded' });
  // ... handler
});$escape$,
