INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2bb5c341-5373-4b7c-8161-66dc72310c06',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST Pagination — Cursor vs Offset, Total Counts, and Infinite Scroll$escape$,
  $escape$Offset pagination (`GET /posts?page=2&limit=20`) is simple but breaks under concurrent writes — items shift between pages as new rows are inserted. Cursor pagination (`GET /posts?after=eyJpZCI6MTAwfQ&limit=20`) uses an opaque pointer (often a base64-encoded `{id, timestamp}`) tied to a stable sort key, making it immune to drift. For infinite scroll in REST APIs, return a `next_cursor` in the response envelope alongside the page data; a `null` cursor signals the end of the collection. Avoid returning `total_count` by default — it requires a full `COUNT(*)` query that doesn't benefit from your cursor index. If clients need it (e.g., for a progress indicator), expose it as an opt-in query param: `?include_total=true`. Use `Link` headers (RFC 5988) alongside the body envelope for machine-readable navigation. Keep cursors short-lived (15–60 min TTL) if they encode sensitive sort criteria, and never expose raw row IDs in cursors — always encode them.$escape$,
  $escape$// REST cursor pagination response envelope
// GET /api/v1/posts?after=eyJpZCI6MTAwfQ&limit=20

{
  "data": [
    { "id": 101, "title": "Cursor Pagination in REST" },
    { "id": 102, "title": "REST Link Headers" }
  ],
  "pagination": {
    "next_cursor": "eyJpZCI6MTAyfQ",
    "prev_cursor": "eyJpZCI6MTAxfQ",
    "has_more": true
  }
}

// Link header (RFC 5988)
// Link: </api/v1/posts?after=eyJpZCI6MTAyfQ&limit=20>; rel="next"$escape$,
