INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f890cb49-83d9-4309-93d0-b5ab59f26598',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST API Filtering & Sorting — Query Param Conventions That Scale$escape$,
  $escape$REST has no spec for filtering and sorting, so conventions vary wildly. The most widely adopted pattern uses bracket notation for filters and a `sort` param with prefixed direction: `GET /articles?filter[status]=published&filter[author]=42&sort=-createdAt,title`. The `-` prefix signals descending; no prefix means ascending. This mirrors JSON:API's convention and is unambiguous without needing a separate `order` param.

For range filters, use suffixed operators: `filter[views][gte]=1000&filter[views][lte]=5000`. Avoid encoding operators in values (`views=gte:1000`) — that breaks typed parsing and URL validation.

Pagination belongs alongside: `page[number]=2&page[size]=25` keeps cursor and offset strategies swappable without breaking client contracts.

On the server, never interpolate query params into raw SQL. Map allowed filter fields to a whitelist and use parameterized queries. Expose only indexed columns as sortable — an unindexed `sort=-body` on a large table is a full table scan waiting to happen.$escape$,
  $escape$// Express + Postgres — safe filter/sort parsing
const ALLOWED_FILTERS = ['status', 'authorId'];
const ALLOWED_SORT = ['createdAt', 'title', 'views'];

function parseQuery(query) {
  const filters = {};
  for (const key of ALLOWED_FILTERS) {
    if (query.filter?.[key]) filters[key] = query.filter[key];
  }

  const rawSort = query.sort ?? '-createdAt';
  const dir = rawSort.startsWith('-') ? 'DESC' : 'ASC';
  const col = rawSort.replace(/^-/, '');
  const sort = ALLOWED_SORT.includes(col) ? { col, dir } : { col: 'createdAt', dir: 'DESC' };

  return { filters, sort };
}$escape$,
  $escape$javascript$escape$,
