INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '10ee6e7b-8ff9-4f24-a348-ead1d5bd737f',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST Caching — HTTP Cache Headers, ETags, and CDN Strategy$escape$,
  $escape$REST APIs leverage HTTP's native caching model through response headers. `Cache-Control: max-age=3600, public` tells CDNs and browsers to cache GET responses for an hour without revalidation. For mutable resources, use `Cache-Control: no-cache` paired with an `ETag` — the server returns a hash of the resource body (e.g. `ETag: "a3f4b2c1"`). Clients store it and send `If-None-Match: "a3f4b2c1"` on subsequent requests. If unchanged, the server returns `304 Not Modified` with no body, saving bandwidth. For time-based validation, `Last-Modified` and `If-Modified-Since` serve the same purpose but are less precise. On CDN edges (Cloudflare, AWS CloudFront), `Vary: Accept-Encoding, Authorization` prevents serving cached authenticated responses to unauthenticated users — critical for REST endpoints mixing public and private data. Avoid `Cache-Control: no-store` unless the response contains sensitive data; it disables caching entirely, killing CDN offload rates. Design your REST resource URLs to be cache-key-friendly: stable, canonical, and free of session-specific query params.$escape$,
  $escape$// Express.js REST endpoint with conditional request support
app.get('/api/articles/:id', async (req, res) => {
  const article = await db.articles.findById(req.params.id);
  if (!article) return res.status(404).end();

  const etag = `"${createHash('md5').update(JSON.stringify(article)).digest('hex')}"`;
  res.setHeader('ETag', etag);
  res.setHeader('Cache-Control', 'public, max-age=60, stale-while-revalidate=300');
  res.setHeader('Last-Modified', article.updatedAt.toUTCString());

  if (req.headers['if-none-match'] === etag) {
    return res.status(304).end();
  }

  res.json(article);
});$escape$,
  $escape$javascript$escape$,
