INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd602c69-7b92-492b-bdf1-654bb801a8a6',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST Error Handling — Consistent Responses with problem+json (RFC 7807)$escape$,
  $escape$Ad-hoc error responses break API consumers. RFC 7807 defines `application/problem+json` — a standardized error envelope that every REST client can parse uniformly. The spec mandates five fields: `type` (URI identifying the error class), `title` (human-readable summary), `status` (HTTP status code mirrored in the body), `detail` (instance-specific explanation), and `instance` (URI of the specific occurrence). ASP.NET Core's `ProblemDetails` implements this out of the box — call `Results.Problem()` or `Results.ValidationProblem()` in Minimal APIs and the correct `Content-Type: application/problem+json` header is set automatically. Extend the base object with domain-specific fields (e.g. `traceId`, `errors` map for validation) by subclassing `ProblemDetails`. On the client side, inspect `Content-Type` before parsing — a `problem+json` response signals a structured error regardless of status code, letting you display `detail` directly or log `instance` for support. Never mix plain `application/json` error shapes with `problem+json` on the same API — pick one contract and enforce it via a global exception handler.$escape$,
  $escape$// ASP.NET Core Minimal API — global problem+json exception handler
app.UseExceptionHandler(errApp => errApp.Run(async ctx =>
{
    var feature = ctx.Features.Get<IExceptionHandlerFeature>();
    ctx.Response.ContentType = "application/problem+json";
    ctx.Response.StatusCode = 500;
    await ctx.Response.WriteAsJsonAsync(new ProblemDetails
    {
        Type    = "https://errors.byteai.dev/internal-error",
        Title   = "An unexpected error occurred.",
        Status  = 500,
        Detail  = feature?.Error.Message,
        Instance = ctx.Request.Path
    });
}));$escape$,
