INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a729dd80-a37c-4586-8504-160b64f85839',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST Idempotency — Safe vs Idempotent Methods and Mutation Keys$escape$,
  $escape$RFC 9110 draws a sharp line between safe and idempotent. Safe methods (GET, HEAD, OPTIONS) produce no server-side state changes — clients can call them freely. Idempotent methods (PUT, DELETE, and all safe methods) guarantee that N identical requests leave the same server state as one — no guarantees about response codes, just the outcome. POST is neither: two identical POST /orders requests can create two orders.

The practical problem: networks are unreliable. A POST that times out may have already succeeded server-side, so a retry doubles the mutation. The fix is an idempotency key — a client-generated UUID sent in a header (commonly Idempotency-Key, as Stripe and Adyen standardize). The server caches the response against that key (typically in Redis with a TTL) and replays it on duplicate requests without re-executing the business logic.

PUT is naturally idempotent because it replaces a resource wholesale. PATCH is not guaranteed idempotent — increment-style patches ("add 1 to quantity") are sensitive to retries. Design PATCH bodies as full-replacement diffs or apply idempotency keys to them explicitly.$escape$,
  $escape$// Express middleware: idempotency key guard for POST /orders
import { createClient } from 'redis';
const redis = createClient();

app.post('/orders', async (req, res) => {
  const key = req.headers['idempotency-key'];
  if (!key) return res.status(400).json({ error: 'Idempotency-Key header required' });

  const cached = await redis.get(`idem:${key}`);
  if (cached) return res.status(200).json(JSON.parse(cached));

  const order = await createOrder(req.body);
  await redis.setEx(`idem:${key}`, 86400, JSON.stringify(order));
  res.status(201).json(order);
});$escape$,
  $escape$javascript$escape$,
