INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '767c1566-9761-473b-9658-f99205dacd60',
  '00000000-0000-0000-0000-000000000001',
  $escape$REST API Performance — Compression, Keep-Alive, and HTTP/2 Multiplexing$escape$,
  $escape$Every REST response travels over the wire, so payload size and connection overhead compound fast at scale. Enable gzip or Brotli compression on your server — most clients send `Accept-Encoding: gzip, br` automatically, and compressing JSON typically yields 60–80% size reduction. On the client, avoid creating a new TCP connection per request: HTTP/1.1 Keep-Alive reuses the socket, but you still queue requests serially. HTTP/2 solves this with multiplexing — multiple in-flight REST requests share a single TCP connection via independent streams, eliminating head-of-line blocking. On the server, trim response payloads with sparse fieldsets: expose a `?fields=id,name,status` query param and strip unused keys before serialization. For repeated read-heavy endpoints, set `Cache-Control: max-age` and return `ETag` headers — clients send `If-None-Match` and get a 304 with zero body bytes when nothing changed. Combine these: compressed, cached, multiplexed REST calls over HTTP/2 with field-filtered payloads can reduce bandwidth 5–10x and latency by 40% versus naive HTTP/1.1 with full payloads.$escape$,
  $escape$// Node.js/Express: compression + ETag + sparse fieldsets
import express from 'express';
import compression from 'compression';

const app = express();
app.use(compression({ threshold: 512 })); // gzip responses > 512 bytes
app.set('etag', 'strong');

app.get('/api/users', (req, res) => {
  const fields = req.query.fields?.split(',');
  let data = getAllUsers(); // full objects
  if (fields) {
    data = data.map(u => Object.fromEntries(fields.map(f => [f, u[f]])));
  }
  res.json(data); // ETag auto-computed; gzip applied by middleware
});$escape$,
  $escape$javascript$escape$,
